#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

// Function to calculate the modular inverse
long long modInverse(long long a, long long m) {
    long long m0 = m;
    long long y = 0, x = 1;
    if (m == 1)
        return 0;
    while (a > 1) {
        long long q = a / m;
        long long t = m;
        m = a % m, a = t;
        t = y;
        y = x - q * y;
        x = t;
    }
    if (x < 0)
        x += m0;
    return x;
}

// Function to calculate the polynomial interpolation
long long* interpolate(long long* f, int n) {
    long long* a = (long long*)malloc(n * sizeof(long long));
    for (int i = 0; i < n; i++) {
        long long numerator = f[i];
        long long denominator = 1;
        for (int j = 0; j < n; j++) {
            if (i != j) {
                numerator = (numerator * (j + 1)) % MOD;
                denominator = (denominator * (i - j)) % MOD;
            }
        }
        a[i] = (numerator * modInverse(denominator, MOD)) % MOD;
    }
    return a;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, Q;
        scanf("%d %d", &n, &Q);
        long long* f = (long long*)malloc(n * sizeof(long long));
        for (int i = 0; i < n; i++) {
            scanf("%lld", &f[i]);
        }
        long long* a = interpolate(f, n);
        for (int i = 0; i < Q; i++) {
            long long x;
            scanf("%lld", &x);
            long long result = 0;
            for (int j = 0; j < n; j++) {
                result = (result + a[j] * (x % MOD)) % MOD;
            }
            printf("%lld ", result);
        }
        printf("\n");
    }
    return 0;
}

