            return 0;
        while (a > 1) {
            long q = a / m;
            long t = m;
            m = a % m;
            a = t;
            t = y;
            y = x - q * y;
            x = t;
        }
        if (x < 0)
            x += m0;
        return x;
    }

    // Function to calculate the polynomial interpolation
    static long[] interpolate(long[] f, int n) {
        long[] a = new long[n];
        for (int i = 0; i < n; i++) {
            long numerator = f[i];
            long denominator = 1;
            for (int j = 0; j < n; j++) {
                if (i != j) {
                    numerator = (numerator * (j + 1)) % MOD;
                    denominator = (denominator * (i - j)) % MOD;
